const releases = $input.all().map(item => item.json);

const total = releases.length;

if (total === 0) {
  return {
    total: 0,
    averageConfidence: 0,
    noGoCount: 0,
    goWithRiskCount: 0,
    goCount: 0,
    highestRiskArea: "UNKNOWN",
    mostCommonBlocker: "None"
  };
}

const avg = key =>
  Math.round(
    releases.reduce((sum, r) => sum + Number(r[key] || 0), 0) / total
  );

const countByRecommendation = value =>
  releases.filter(r => r.releaseRecommendation === value).length;

const allBlockers = releases.flatMap(r => r.criticalBlockers || []);

const blockerCount = {};
for (const blocker of allBlockers) {
  blockerCount[blocker] = (blockerCount[blocker] || 0) + 1;
}

const mostCommonBlocker =
  Object.entries(blockerCount).sort((a, b) => b[1] - a[1])[0]?.[0] || "None";

const riskAreas = {
  security: avg("securityScore"),
  performance: avg("performanceScore"),
  business: avg("businessScore"),
  observability: avg("observabilityScore"),
  reliability: avg("reliabilityScore"),
  compliance: avg("complianceScore")
};

const highestRiskArea =
  Object.entries(riskAreas).sort((a, b) => a[1] - b[1])[0]?.[0] || "UNKNOWN";

return {
  total,
  averageConfidence: avg("releaseConfidenceScore"),
  averageSecurityScore: avg("securityScore"),
  averagePerformanceScore: avg("performanceScore"),
  averageBusinessScore: avg("businessScore"),
  averageObservabilityScore: avg("observabilityScore"),
  averageReliabilityScore: avg("reliabilityScore"),
  averageComplianceScore: avg("complianceScore"),

  noGoCount: countByRecommendation("NO_GO"),
  goWithRiskCount: countByRecommendation("GO_WITH_RISK"),
  goCount: countByRecommendation("GO"),

  highestRiskArea,
  mostCommonBlocker
};
